def rate_limit_check(store, key, max_attempts, window_seconds):
    """Check and enforce rate limiting."""
    now = time.time()
    if key in store:
        attempts = [t for t in store[key] if now - t < window_seconds]
        store[key] = attempts
        if len(attempts) >= max_attempts:
            return False
    return True


def rate_limit_record(store, key):
    """Record an attempt for rate limiting."""
    now = time.time()
    if key not in store:
        store[key] = []
    store[key].append(now)


def send_email(to_email, subject, body):
    """Send an email. In production, use a proper email service."""
    try:
        msg = MIMEMultipart()
        msg['From'] = SMTP_FROM
        msg['To'] = to_email
        msg['Subject'] = subject
        msg.attach(MIMEText(body, 'html'))

        if SMTP_HOST == 'localhost' and not SMTP_USER:
            # Development mode - just log the email
            print(f"[DEV EMAIL] To: {to_email}, Subject: {subject}")
            print(f"[DEV EMAIL] Body: {body}")
            return True

        with smtplib.SMTP(SMTP_HOST, SMTP_PORT) as server:
            server.starttls()
            if SMTP_USER and SMTP_PASS:
                server.login(SMTP_USER, SMTP_PASS)
            server.send_message(msg)
        return True
    except Exception as e:
        print(f"Failed to send email: {e}")
        return False


def generate_secure_token():
    """Generate a cryptographically secure token."""
    return secrets.token_urlsafe(48)


def hash_token(token):
    """Hash a token for secure storage."""
    return hashlib.sha256(token.encode()).hexdigest()


def require_auth(f):
    """Decorator to require full authentication (password + MFA if enabled)."""
    @wraps(f)
    def decorated(*args, **kwargs):
        user_id = session.get('user_id')
        if not user_id:
            return jsonify({'error': 'Authentication required'}), 401

        # CRITICAL: Check that MFA verification is complete if MFA is enabled
        if user_id in users_db and users_db[user_id].get('mfa_enabled'):
            if not session.get('mfa_verified'):
                return jsonify({'error': 'MFA verification required'}), 403

        if not session.get('fully_authenticated'):
            return jsonify({'error': 'Full authentication required'}), 401

        return f(*args, **kwargs)
    return decorated


def require_password_auth(f):
    """Decorator to require at least password authentication (for MFA setup steps)."""
    @wraps(f)
    def decorated(*args, **kwargs):
        user_id = session.get('user_id')
        if not user_id:
            return jsonify({'error': 'Authentication required'}), 401
        if not session.get('password_verified'):
            return jsonify({'error': 'Password authentication required'}), 401
        return f(*args, **kwargs)
    return decorated


@app.route('/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = data.get('email', '').strip().lower()
    password = data.get('password', '')

    if not email or not password:
        return jsonify({'error': 'Email and password are required'}), 400

    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400

    # Check if user already exists
    for uid, user in users_db.items():
        if user['email'] == email:
            # Don't reveal that the email is already registered
            return jsonify({'message': 'If the email is valid, registration will proceed'}), 200

    user_id = secrets.token_hex(16)
    users_db[user_id] = {
        'user_id': user_id,
        'email': email,
        'password_hash': generate_password_hash(password),
        'mfa_enabled': False,
        'mfa_secret': None,
        'mfa_backup_codes': [],
        'mfa_reset_in_progress': False,
        'created_at': datetime.utcnow().isoformat(),
    }

    return jsonify({'message': 'User registered successfully', 'user_id': user_id}), 201


@app.route('/login', methods=['POST'])
def login():
    """
    Login endpoint. Returns appropriate response based on MFA status.
    If MFA is enabled, requires a second step to verify MFA code.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = data.get('email', '').strip().lower()
    password = data.get('password', '')

    if not email or not password:
        return jsonify({'error': 'Email and password are required'}), 400

    # Rate limiting
    if not rate_limit_check(login_attempts, email, MAX_LOGIN_ATTEMPTS, RATE_LIMIT_WINDOW_SECONDS):
        return jsonify({'error': 'Too many login attempts. Please try again later.'}), 429

    # Find user by email
    user = None
    for uid, u in users_db.items():
        if u['email'] == email:
            user = u
            break

    if not user or not check_password_hash(user['password_hash'], password):
        rate_limit_record(login_attempts, email)
        return jsonify({'error': 'Invalid email or password'}), 401

    user_id = user['user_id']

    # Set session: password is verified
    session['user_id'] = user_id
    session['password_verified'] = True
    session['login_time'] = datetime.utcnow().isoformat()

    if user.get('mfa_enabled') and not user.get('mfa_reset_in_progress'):
        # MFA is enabled - require second factor
        # DO NOT set fully_authenticated or mfa_verified yet
        session['mfa_verified'] = False
        session['fully_authenticated'] = False

        # Create a pending MFA session
        pending_id = secrets.token_hex(16)
        mfa_pending_sessions[pending_id] = {
            'user_id': user_id,
            'created_at': time.time(),
            'expires_at': time.time() + 300,  # 5 minutes to complete MFA
        }
        session['mfa_pending_id'] = pending_id

        return jsonify({
            'message': 'Password verified. MFA verification required.',
            'mfa_required': True,
            'mfa_pending_id': pending_id,
        }), 200
    else:
        # No MFA or MFA reset in progress - fully authenticated
        session['mfa_verified'] = True
        session['fully_authenticated'] = True

        # If MFA reset was in progress, clear the flag after successful login
        if user.get('mfa_reset_in_progress'):
            user['mfa_reset_in_progress'] = False

        return jsonify({
            'message': 'Login successful',
            'mfa_required': False,
            'user_id': user_id,
        }), 200


@app.route('/login/mfa-verify', methods=['POST'])
def login_mfa_verify():
    """Second step of login: verify MFA code."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    user_id = session.get('user_id')
    if not user_id or not session.get('password_verified'):
        return jsonify({'error': 'Please complete password authentication first'}), 401

    pending_id = session.get('mfa_pending_id')
    if not pending_id or pending_id not in mfa_pending_sessions:
        return jsonify({'error': 'No pending MFA verification found. Please login again.'}), 401

    pending = mfa_pending_sessions[pending_id]
    if time.time() > pending['expires_at']:
        del mfa_pending_sessions[pending_id]
        session.clear()
        return jsonify({'error': 'MFA verification expired. Please login again.'}), 401

    if pending['user_id'] != user_id:
        session.clear()
        return jsonify({'error': 'Session mismatch. Please login again.'}), 401

    user = users_db.get(user_id)
    if not user:
        session.clear()
        return jsonify({'error': 'User not found'}), 404

    mfa_code = data.get('mfa_code', '').strip()
    backup_code = data.get('backup_code', '').strip()

    verified = False

    if mfa_code:
        # Verify TOTP code
        if user.get('mfa_secret'):
            totp = pyotp.TOTP(user['mfa_secret'])
            # Allow 1 window of drift (30 seconds)
            if totp.verify(mfa_code, valid_window=1):
                verified = True

    elif backup_code:
        # Verify backup code
        backup_code_hash = hashlib.sha256(backup_code.encode()).hexdigest()
        if backup_code_hash in user.get('mfa_backup_codes', []):
            user['mfa_backup_codes'].remove(backup_code_hash)
            verified = True

    if not verified:
        rate_limit_record(login_attempts, user['email'])
        return jsonify({'error': 'Invalid MFA code'}), 401

    # MFA verified - grant full access
    session['mfa_verified'] = True
    session['fully_authenticated'] = True

    # Clean up pending session
    if pending_id in mfa_pending_sessions:
        del mfa_pending_sessions[pending_id]
    if 'mfa_pending_id' in session:
        del session['mfa_pending_id']

    return jsonify({
        'message': 'MFA verification successful. Login complete.',
        'user_id': user_id,
    }), 200


