@app.route('/mfa/setup', methods=['POST'])
@require_auth
def mfa_setup():
    """
    Begin MFA setup. Generates a TOTP secret and returns QR code.
    User must confirm with a valid code before MFA is actually enabled.
    """
    user_id = session['user_id']
    user = users_db.get(user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if user.get('mfa_enabled'):
        return jsonify({'error': 'MFA is already enabled. Disable it first to reconfigure.'}), 400

    # Generate new TOTP secret
    secret = pyotp.random_base32()
    user['mfa_pending_secret'] = secret

    # Generate provisioning URI for QR code
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(
        name=user['email'],
        issuer_name='MFA Management System'
    )

    # Generate QR code as base64
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    buffer = io.BytesIO()
    img.save(buffer, format='PNG')
    qr_base64 = base64.b64encode(buffer.getvalue()).decode()

    return jsonify({
        'message': 'MFA setup initiated. Scan the QR code and confirm with a valid code.',
        'secret': secret,
        'qr_code': f'data:image/png;base64,{qr_base64}',
        'provisioning_uri': provisioning_uri,
    }), 200


@app.route('/mfa/confirm', methods=['POST'])
@require_auth
def mfa_confirm():
    """
    Confirm MFA setup by providing a valid TOTP code.
    This actually enables MFA on the account.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    user_id = session['user_id']
    user = users_db.get(user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if user.get('mfa_enabled'):
        return jsonify({'error': 'MFA is already enabled'}), 400

    pending_secret = user.get('mfa_pending_secret')
    if not pending_secret:
        return jsonify({'error': 'No MFA setup in progress. Call /mfa/setup first.'}), 400

    mfa_code = data.get('mfa_code', '').strip()
    if not mfa_code:
        return jsonify({'error': 'MFA code is required'}), 400

    # Verify the code against the pending secret
    totp = pyotp.TOTP(pending_secret)
    if not totp.verify(mfa_code, valid_window=1):
        return jsonify({'error': 'Invalid MFA code. Please try again.'}), 400

    # Generate backup codes
    backup_codes = [secrets.token_hex(4).upper() for _ in range(10)]
    backup_code_hashes = [hashlib.sha256(code.encode()).hexdigest() for code in backup_codes]

    # Enable MFA
    user['mfa_secret'] = pending_secret
    user['mfa_enabled'] = True
    user['mfa_backup_codes'] = backup_code_hashes
    user['mfa_enabled_at'] = datetime.utcnow().isoformat()
    del user['mfa_pending_secret']

    return jsonify({
        'message': 'MFA has been enabled successfully.',
        'backup_codes': backup_codes,
        'warning': 'Save these backup codes in a safe place. They will not be shown again.',
    }), 200


@app.route('/mfa/disable', methods=['POST'])
@require_auth
def mfa_disable():
    """
    Disable MFA. Requires current password and a valid MFA code for security.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    user_id = session['user_id']
    user = users_db.get(user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if not user.get('mfa_enabled'):
        return jsonify({'error': 'MFA is not enabled'}), 400

    password = data.get('password', '')
    mfa_code = data.get('mfa_code', '').strip()

    if not password:
        return jsonify({'error': 'Current password is required'}), 400

    if not mfa_code:
        return jsonify({'error': 'Current MFA code is required'}), 400

    # Verify password
    if not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid password'}), 401

    # Verify MFA code
    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(mfa_code, valid_window=1):
        return jsonify({'error': 'Invalid MFA code'}), 401

    # Disable MFA
    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_backup_codes'] = []
    user['mfa_reset_in_progress'] = False
    user['mfa_disabled_at'] = datetime.utcnow().isoformat()

    return jsonify({'message': 'MFA has been disabled successfully.'}), 200


