@app.route('/reset-mfa', methods=['POST'])
def reset_mfa_request():
    """
    Request an MFA reset. Sends a secure reset link to the registered email.
    This endpoint is intentionally vague in its responses to prevent email enumeration.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = data.get('email', '').strip().lower()
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Rate limiting on reset requests
    if not rate_limit_check(reset_attempts, email, MAX_RESET_ATTEMPTS, RATE_LIMIT_WINDOW_SECONDS):
        return jsonify({
            'message': 'If an account with that email exists and has MFA enabled, '
                       'a reset link has been sent.'
        }), 200

    rate_limit_record(reset_attempts, email)

    # Generic response to prevent email enumeration
    generic_response = {
        'message': 'If an account with that email exists and has MFA enabled, '
                   'a reset link has been sent to that email address.'
    }

    # Find user by email
    user = None
    for uid, u in users_db.items():
        if u['email'] == email:
            user = u
            break

    if not user:
        # Don't reveal that the email doesn't exist
        return jsonify(generic_response), 200

    if not user.get('mfa_enabled'):
        # Don't reveal MFA status
        return jsonify(generic_response), 200

    # Invalidate any existing reset tokens for this user
    tokens_to_remove = []
    for token_hash, token_data in reset_tokens_db.items():
        if token_data['user_id'] == user['user_id']:
            tokens_to_remove.append(token_hash)
    for token_hash in tokens_to_remove:
        del reset_tokens_db[token_hash]

    # Generate secure reset token
    raw_token = generate_secure_token()
    token_hash = hash_token(raw_token)

    reset_tokens_db[token_hash] = {
        'user_id': user['user_id'],
        'email': email,
        'created_at': datetime.utcnow(),
        'expires_at': datetime.utcnow() + timedelta(minutes=RESET_TOKEN_EXPIRY_MINUTES),
        'used': False,
        'ip_address': request.remote_addr,
    }

    # Build reset link
    reset_link = f"{BASE_URL}/reset-mfa/confirm?token={raw_token}"

    # Send email
    email_body = f"""
    <html>
    <body>
        <h2>MFA Reset Request</h2>
        <p>You (or someone else) requested to reset Multi-Factor Authentication on your account.</p>
        <p>If you did not request this, please ignore this email and ensure your account is secure.</p>
        <p>To reset your MFA, click the link below:</p>
        <p><a href="{reset_link}">Reset MFA</a></p>
        <p>This link will expire in {RESET_TOKEN_EXPIRY_MINUTES} minutes.</p>
        <p><strong>Warning:</strong> After resetting MFA, your account will temporarily be accessible
        with just your password. We strongly recommend re-enabling MFA immediately after logging in.</p>
        <p>Request details:</p>
        <ul>
            <li>Time: {datetime.utcnow().isoformat()} UTC</li>
            <li>IP: {request.remote_addr}</li>
        </ul>
    </body>
    </html>
    """

    send_email(email, 'MFA Reset Request', email_body)

    return jsonify(generic_response), 200


@app.route('/reset-mfa/confirm', methods=['GET', 'POST'])
def reset_mfa_confirm():
    """
    Confirm MFA reset using the token from the email link.
    GET: Validate token and show confirmation page info.
    POST: Actually perform the MFA reset.
    """
    if request.method == 'GET':
        token = request.args.get('token', '')
    else:
        data = request.get_json() or {}
        token = data.get('token', '') or request.args.get('token', '')

    if not token:
        return jsonify({'error': 'Reset token is required'}), 400

    token_hash = hash_token(token)
    token_data = reset_tokens_db.get(token_hash)

    if not token_data:
        return jsonify({'error': 'Invalid or expired reset token'}), 400

    if token_data['used']:
        return jsonify({'error': 'This reset token has already been used'}), 400

    if datetime.utcnow() > token_data['expires_at']:
        # Clean up expired token
        del reset_tokens_db[token_hash]
        return jsonify({'error': 'Reset token has expired. Please request a new one.'}), 400

    user = users_db.get(token_data['user_id'])
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if request.method == 'GET':
        # Just validate and return info
        return jsonify({
            'message': 'Token is valid. Submit a POST request to confirm MFA reset.',
            'email': user['email'],
            'expires_at': token_data['expires_at'].isoformat(),
        }), 200

    # POST: Perform the reset
    # Require password confirmation for the reset
    data = request.get_json() or {}
    password = data.get('password', '')

    if not password:
        return jsonify({'error': 'Password confirmation is required to reset MFA'}), 400

    if not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid password'}), 401

    # Mark token as used
    token_data['used'] = True
    token_data['used_at'] = datetime.utcnow()

    # Disable MFA but set reset_in_progress flag
    # This flag allows password-only login but reminds to re-enable MFA
    user['mfa_enabled'] = False
    user['mfa_secret'] = None
    user['mfa_backup_codes'] = []
    user['mfa_reset_in_progress'] = True
    user['mfa_reset_at'] = datetime.utcnow().isoformat()
    user['mfa_reset_ip'] = request.remote_addr

    # Send notification email about the reset
    notification_body = f"""
    <html>
    <body>
        <h2>MFA Has Been Reset</h2>
        <p>Multi-Factor Authentication has been disabled on your account via the reset process.</p>
        <p>You can now log in with just your password.</p>
        <p><strong>Important:</strong> We strongly recommend re-enabling MFA immediately after logging in
        to keep your account secure.</p>
        <p>Reset details:</p>
        <ul>
            <li>Time: {datetime.utcnow().isoformat()} UTC</li>
            <li>IP: {request.remote_addr}</li>
        </ul>
        <p>If you did not perform this action, please change your password immediately and contact support.</p>
    </body>
    </html>
    """
    send_email(user['email'], 'MFA Has Been Reset on Your Account', notification_body)

    # Invalidate all other reset tokens for this user
    tokens_to_remove = []
    for th, td in reset_tokens_db.items():
        if td['user_id'] == user['user_id'] and th != token_hash:
            tokens_to_remove.append(th)
    for th in tokens_to_remove:
        del reset_tokens_db[th]

    return jsonify({
        'message': 'MFA has been reset successfully. You can now log in with your password. '
                   'Please re-enable MFA as soon as possible.',
    }), 200


